#include <bits/stdc++.h>
using namespace std;

const int mod=998244353;

int n,k,m,p[1010],inv[10010],f[10010][15],ans;

int main(){
    scanf("%d%d%d",&n,&k,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&p[i]);
    inv[0]=inv[1]=1;
    for(int i=2;i<=m;i++)
        inv[i]=1ll*(mod-mod/i)*inv[mod%i]%mod;
    k=n-k+1;
    f[0][0]=m;
    for(int i=1;i<=n;i++)
        for(int j=m;j>=p[i];j--)
            for(int l=1;l<=k;l++)
                f[j][l]=(f[j][l]+1ll*max(1,j-p[i])*inv[j]%mod*(f[j-p[i]][l-1]-f[j-p[i]][l]))%mod;
    for(int i=1;i<=m;i++)
        ans=(ans+f[i][k])%mod;
    printf("%d",(ans+mod)%mod);
    return 0;
}
